// src/errors/index.ts — Complete error type registry

const BASE = 'https://api.payments.example/errors';

// ── Authentication Errors ──────────────────────────────────────────────────

export class AuthenticationRequiredError extends AppError {
  readonly type = `${BASE}/authentication-required`;
  readonly title = 'Authentication Required';
  readonly status = 401;
}

export class TokenExpiredError extends AppError {
  readonly type = `${BASE}/token-expired`;
  readonly title = 'Token Expired';
  readonly status = 401;
}

export class TokenInvalidError extends AppError {
  readonly type = `${BASE}/token-invalid`;
  readonly title = 'Invalid Token';
  readonly status = 401;
}

/**
 * Specifically for HS256 tokens — we reject them with a clear message
 * so operators know exactly why validation failed.
 * This enforces SEC-2025-041 at the error layer.
 */
export class TokenAlgorithmRejectedError extends AppError {
  readonly type = `${BASE}/token-algorithm-rejected`;
  readonly title = 'Token Algorithm Rejected';
  readonly status = 401;
}

export class PermissionDeniedError extends AppError {
  readonly type = `${BASE}/permission-denied`;
  readonly title = 'Permission Denied';
  readonly status = 403;
}

// ── Rate Limit Errors ──────────────────────────────────────────────────────

export class RateLimitExceededError extends AppError {
  readonly type = `${BASE}/rate-limited`;
  readonly title = 'Rate Limit Exceeded';
  readonly status = 429;

  // retryAfterSeconds is required — enforces the SLA obligation
  constructor(
    detail: string,
    readonly retryAfterSeconds: number,
    extensions: Record<string, unknown> = {}
  ) {
    super(detail, { retry_after: retryAfterSeconds, ...extensions });
    if (!Number.isInteger(retryAfterSeconds) || retryAfterSeconds < 0) {
      // Fail loudly in development; in production this would still send
      // a valid response but we want to catch this during testing
      throw new Error(
        `RateLimitExceededError requires a non-negative integer retryAfterSeconds, got: ${retryAfterSeconds}`
      );
    }
  }
}

// ── Validation Errors ──────────────────────────────────────────────────────

export interface ValidationFailure {
  field: string;
  message: string;
}

export class ValidationFailedError extends AppError {
  readonly type = `${BASE}/validation-failed`;
  readonly title = 'Validation Failed';
  readonly status = 400;

  constructor(failures: ValidationFailure[]) {
    super(
      `${failures.length} validation error(s) in request body`,
      { validation_errors: failures }
