### 1.3 Global Error Handler

```typescript
// src/middleware/errorHandler.ts

import { Request, Response, NextFunction } from 'express';
import { AppError, RateLimitExceededError, TokenAlgorithmRejectedError } from '../errors';
import { logger } from '../lib/logger';

const IS_PRODUCTION = process.env.NODE_ENV === 'production';

/**
 * Terminal error handling middleware.
 *
 * MUST be registered last in the Express middleware stack.
 * All errors — from route handlers, middleware, and async code —
 * must be passed to next(err) to reach this handler.
 *
 * Guarantees:
 * - Every response uses RFC 9457 format (ADR-003)
 * - Content-Type is always application/problem+json
 * - Rate limit errors always include Retry-After (partner SLA)
 * - Stack traces never appear in production responses
 * - trace_id is always present for correlation
 */
export function globalErrorHandler(
  err: unknown,
  req: Request,
  res: Response,
  // next is required by Express's 4-argument error handler signature
  // even if unused — removing it breaks error handler detection
  _next: NextFunction
): void {
  const traceId = req.context?.traceId ?? 'unknown';
  const instance = req.originalUrl;

  // ── Classify the error ───────────────────────────────────────────────────

  let appError: AppError;

  if (err instanceof AppError) {
    appError = err;
  } else {
    // Unknown error — likely a bug or unhandled library exception.
    // Log the full error internally but return a generic 500.
    // Never expose internal details to the client.
    logger.error('Unhandled error', {
      traceId,
      error: err instanceof Error ? err.message : String(err),
      stack: err instanceof Error ? err.stack : undefined,
      path: instance,
    });

    appError = new InternalServerError(
      'An unexpected error occurred. Please try again or contact support if the problem persists.'
    );
  }

  // ── Log application errors ───────────────────────────────────────────────

  // 5xx errors are bugs or infrastructure failures — log as ERROR
  // 4xx errors are client mistakes — log as WARN (less noise)
  const logLevel = appError.status >= 500 ? 'error' : 'warn';
  logger[logLevel]('Request error', {
    traceId,
    type: appError.type,
    status: appError.status,
    detail: appError.detail,
    path: instance,
    // Log the original error stack for 5xx even if we don't send it
    ...(appError.status >= 500 && err instanceof Error
      ? { stack: err.stack }
      : {}),
  });

  // ── Build RFC 9457 response body ─────────────────────────────────────────

  const body: Record<string, unknown> = {
    type: appError.type,
    title: appError.title,
    status: appError.status,
    detail: appError.detail,
    instance,
    trace_id: traceId,
    // Spread extension fields (validation_errors, retry_after, etc.)
    ...appError.extensions,
  };

  // In non-production, add debug info to help developers.
  // This block must never run in production.
  if (!IS_PRODUCTION && err instanceof Error && !(err instanceof AppError)) {
    body['debug'] = {
      message: err.message,
      // Stack traces are acceptable in development only
      stack: err.stack?.split('\n').slice(0, 10),
    };
  }

  // ── Set response headers ─────────────────────────────────────────────────

  res.setHeader('Content-Type', 'application/problem+json');

  // Rate limit headers — required on 429 responses per ADR-002 and partner SLA
  if (appError instanceof RateLimitExceededError) {
    const retryAfter = appError.retryAfterSeconds;

    // Retry-After is the contractual obligation — set it first
    res.setHeader('Retry-After', String(retryAfter));

    // The remaining rate limit headers are sourced from the error extensions
    // (set by the rate limiting middleware before throwing)
    const { limit, remaining, reset } = appError.extensions as {
      limit?: number;
      remaining?: number;
      reset?: number;
    };

    if (limit !== undefined) res.setHeader('X-RateLimit-Limit', String(limit));
    if (remaining !== undefined) res.setHeader('X-RateLimit-Remaining', String(remaining));
    if (reset !== undefined) res.setHeader('X-RateLimit-Reset', String(reset));
  }

  // WWW-Authenticate header for 401 responses (RFC 6750 compliance)
  if (appError.status === 401) {
    res.setHeader(
      'WWW-Authenticate',
      'Bearer realm="payments-api", error="invalid_token"'
    );
  }

  // ── Send response ────────────────────────────────────────────────────────

  res.status(appError.status).json(body);
}

// Internal server error — defined here to avoid circular imports
class InternalServerError extends AppError {
  readonly type = 'https://api.payments.example/errors/internal-server-error';
  readonly title = 'Internal Server Error';
  readonly status = 500;
}
```

### 1.4 Request Context Middleware

The error handler depends on `req.context.traceId`. This must be set before any other middleware runs.

```typescript
// src/middleware/requestContext.ts

import { Request, Response, NextFunction } from 'express';
import { randomUUID } from 'crypto';

declare global {
  namespace Express {
    interface Request {
      context: {
        traceId: string;
        startTime: number;
      };
    }
  }
}

export function requestContext(
  req: Request,
  _res: Response,
  next: NextFunction
): void {
  // Accept an incoming trace ID from upstream (e.g., API gateway)
  // or generate a new one. This enables distributed tracing.
  const incomingTraceId = req.headers['x-trace-id'];
  const traceId =
    typeof incomingTraceId === 'string' && incomingTraceId.length > 0
      ? incomingTraceId
      : randomUUID();

  req.context = {
    traceId,
    startTime: Date.now(),
  };

  next();
}
```

